import{c as i,O as l,i as e,m as r}from"./chunks/framework.BWIk71Uc.js";const g=JSON.parse('{"title":"面试准备路线","description":"基于已有文章组织的面试准备路线，含一周冲刺计划。","frontmatter":{"title":"面试准备路线","description":"基于已有文章组织的面试准备路线，含一周冲刺计划。","date":"2026-05-30T00:00:00.000Z","tags":["面试","路线","准备"],"category":"writing-guide","status":"reviewing","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"writing-guide/interview-prep.md","filePath":"writing-guide/interview-prep.md","lastUpdated":1780128182000}'),n={name:"writing-guide/interview-prep.md"};function t(s,a,d,o,h,p){return l(),e("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1780099200000"},[...a[0]||(a[0]=[r('<h1 id="面试准备路线" tabindex="-1">面试准备路线 <a class="header-anchor" href="#面试准备路线" aria-label="Permalink to “面试准备路线”">​</a></h1><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to “使用方式”">​</a></h2><ol><li>按路线顺序阅读 stable / reviewing 文章</li><li>标记仍需真实案例补充的内容</li><li>结合项目复盘准备项目表达</li><li>模拟追问练习</li></ol><h2 id="java-面试" tabindex="-1">Java 面试 <a class="header-anchor" href="#java-面试" aria-label="Permalink to “Java 面试”">​</a></h2><p><strong>高频问题</strong>：集合、并发、JVM</p><ul><li><a href="/notes/java/basics/">Java 基础</a></li><li><a href="/notes/java/collection/">集合框架</a></li><li><a href="/notes/java/concurrent/">Java 并发编程</a></li><li><a href="/notes/java/jvm/">JVM</a></li><li><a href="/interview/java/">Java 面试题</a></li></ul><p><strong>可能追问</strong>：</p><ul><li>HashMap 底层实现？扩容机制？</li><li>synchronized 和 ReentrantLock 区别？</li><li>线程池参数如何设置？</li><li>GC 算法对比？</li></ul><h2 id="spring-面试" tabindex="-1">Spring 面试 <a class="header-anchor" href="#spring-面试" aria-label="Permalink to “Spring 面试”">​</a></h2><p><strong>高频问题</strong>：IOC、AOP、Boot 自动配置</p><ul><li><a href="/notes/spring/spring-boot/">Spring Boot</a></li><li><a href="/notes/spring/spring-mvc/">Spring MVC</a></li><li><a href="/notes/spring/spring-cloud/">Spring Cloud</a></li><li><a href="/interview/spring/">Spring 面试题</a></li></ul><p><strong>可能追问</strong>：</p><ul><li>Bean 生命周期？</li><li>自动配置原理？</li><li>微服务治理？</li></ul><h2 id="mysql-面试" tabindex="-1">MySQL 面试 <a class="header-anchor" href="#mysql-面试" aria-label="Permalink to “MySQL 面试”">​</a></h2><p><strong>高频问题</strong>：索引、事务、锁、慢 SQL</p><ul><li><a href="/notes/database/mysql/">MySQL 基础</a></li><li><a href="/interview/mysql/">MySQL 面试题</a></li></ul><p><strong>可能追问</strong>：</p><ul><li>索引失效场景？</li><li>事务隔离级别？</li><li>如何排查慢 SQL？</li><li>EXPLAIN 怎么看？</li></ul><h2 id="redis-面试" tabindex="-1">Redis 面试 <a class="header-anchor" href="#redis-面试" aria-label="Permalink to “Redis 面试”">​</a></h2><p><strong>高频问题</strong>：数据结构、缓存问题、持久化</p><ul><li><a href="/notes/database/redis/">Redis 基础</a></li></ul><p><strong>可能追问</strong>：</p><ul><li>缓存击穿 / 穿透 / 雪崩？</li><li>Redis 和 Memcached 区别？</li><li>持久化方式对比？</li></ul><h2 id="项目面试" tabindex="-1">项目面试 <a class="header-anchor" href="#项目面试" aria-label="Permalink to “项目面试”">​</a></h2><p><strong>高频问题</strong>：项目背景、技术选型、核心难点</p><ul><li><a href="/interview/project/">项目面试复盘</a></li><li><a href="/projects/mall-swarm/">mall-swarm 项目</a></li><li><a href="/projects/docs-site/">文档站项目</a></li></ul><p><strong>可能追问</strong>：</p><ul><li>为什么选这个技术栈？</li><li>遇到的最大挑战？</li><li>如何保证代码质量？</li></ul><h2 id="一周冲刺计划" tabindex="-1">一周冲刺计划 <a class="header-anchor" href="#一周冲刺计划" aria-label="Permalink to “一周冲刺计划”">​</a></h2><h3 id="day-1-java-基础与集合" tabindex="-1">Day 1：Java 基础与集合 <a class="header-anchor" href="#day-1-java-基础与集合" aria-label="Permalink to “Day 1：Java 基础与集合”">​</a></h3><ul><li>复习 Java 基础笔记</li><li>重点看 HashMap、ArrayList 源码</li><li>准备 3 个集合相关追问</li></ul><h3 id="day-2-并发与-jvm" tabindex="-1">Day 2：并发与 JVM <a class="header-anchor" href="#day-2-并发与-jvm" aria-label="Permalink to “Day 2：并发与 JVM”">​</a></h3><ul><li>复习线程池、锁机制</li><li>重点看 synchronized、ReentrantLock</li><li>准备 GC 算法对比</li></ul><h3 id="day-3-mysql-与-redis" tabindex="-1">Day 3：MySQL 与 Redis <a class="header-anchor" href="#day-3-mysql-与-redis" aria-label="Permalink to “Day 3：MySQL 与 Redis”">​</a></h3><ul><li>复习索引、事务、锁</li><li>重点看 EXPLAIN 使用</li><li>准备缓存问题对比</li></ul><h3 id="day-4-spring" tabindex="-1">Day 4：Spring <a class="header-anchor" href="#day-4-spring" aria-label="Permalink to “Day 4：Spring”">​</a></h3><ul><li>复习 IOC、AOP 原理</li><li>重点看自动配置</li><li>准备 Bean 生命周期</li></ul><h3 id="day-5-项目表达" tabindex="-1">Day 5：项目表达 <a class="header-anchor" href="#day-5-项目表达" aria-label="Permalink to “Day 5：项目表达”">​</a></h3><ul><li>用 STAR 法则准备项目描述</li><li>准备技术选型理由</li><li>准备核心难点和解决方案</li></ul><h3 id="day-6-模拟追问" tabindex="-1">Day 6：模拟追问 <a class="header-anchor" href="#day-6-模拟追问" aria-label="Permalink to “Day 6：模拟追问”">​</a></h3><ul><li>模拟面试官追问</li><li>记录回答不好的问题</li><li>补充知识点</li></ul><h3 id="day-7-复盘补缺" tabindex="-1">Day 7：复盘补缺 <a class="header-anchor" href="#day-7-复盘补缺" aria-label="Permalink to “Day 7：复盘补缺”">​</a></h3><ul><li>回顾一周标记的问题</li><li>补充薄弱环节</li><li>调整心态</li></ul>',43)])])}const u=i(n,[["render",t]]);export{g as __pageData,u as default};
